import{_ as i,a,M as e,o as t}from"./chunks/framework.BzjwFSRk.js";const r="/assets/unVRaEUOLJo.CmDzWTBi.jpg",p=JSON.parse('{"title":"Принципы и правила Минского хакерспейса","description":"","frontmatter":{"title":"Принципы и правила Минского хакерспейса","date":"2018-08-30","cover":"unVRaEUOLJo.jpg"},"headers":[],"relativePath":"theory/research/minsk-rules/index.md","filePath":"theory/research/minsk-rules/index.md"}'),o={name:"theory/research/minsk-rules/index.md"};function s(n,l,u,h,d,c){return t(),a("div",null,[...l[0]||(l[0]=[e('<h1 id="наши-принципы" tabindex="-1">Наши принципы <a class="header-anchor" href="#наши-принципы" aria-label="Permalink to &quot;Наши принципы&quot;">​</a></h1><p>Хакерспейс (ХС) — независимая некоммерческая общественная мастерская-клуб. Из этого вырастают принципы участия и пользования им:</p><ol><li>Все участники помогают создавать пространство, комфортное для работы.</li><li>Участники вкладывают(contribute) больше, чем потребляют(consume).</li><li>Каждый может заниматься тем проектом и той деятельностью, которой хочет, в разумных рамках, не мешая другим.</li><li>Посетители хакерспейса делятся на две группы: постоянные участники и гости.</li><li>Постоянные участники — оплатившие ежемесячный взнос (см. тарифы). Они имеют право доступа в ХС в любой момент.</li><li>Гости — все остальные. Гость может прийти в день открытых дверей или к конкретному постоянному участнику (и тогда может работать вместе с ним).</li><li>Посетитель может пользоваться всем общественным оборудованием и материалами хакерспейса.</li><li>В мастерской есть общественные оборудование и материалы, а есть чьи-то личные. Если сомневаетесь, можно ли разобрать на запчасти конкретный прибор или пустить в дело лист фанеры — спросите об этом!</li><li>Организационные и принципиальные технические решения принимаются путём долгих, нудных и пустопорожних обсуждений в рассылке или в самом хакерспейсе. Или кто-то просто берёт на себя ответственность за решение и делает 😃</li><li>И вообще, никакие &quot;Мне не нравится&quot; или &quot;Давайте сделаем вот так..&quot; не принимаются. Есть &quot;Мне не нравится, и я сделаю лучше&quot; и &quot;Давайте я сделаю вот так&quot;. Just do it.</li></ol><h2 id="бытовые-но-очень-важные-правила" tabindex="-1">Бытовые, но очень важные правила: <a class="header-anchor" href="#бытовые-но-очень-важные-правила" aria-label="Permalink to &quot;Бытовые, но очень важные правила:&quot;">​</a></h2><ul><li><strong>Уходишь – убери за собой</strong></li><li>Постарайся оставить хакерспейс в лучшем состоянии, чем он был, когда ты пришел</li><li>Оставь рабочие столы пустыми</li><li>Не забудь про паяльный стол, сверлильный станок, верстаки и так далее</li><li>Подмети за собой остатки изоляции, опилки и стружки</li><li>Посуда должна быть вымыта</li><li>Если мусор не помещается в ведро без физических усилий – вынеси его</li><li>У нас нет выделенных кому-то конкретному рабочих мест</li><li>Даже если ты <ul><li>никому не мешаешь</li><li>совсем</li><li>точно уверен, что завтра утром вернёшься и продолжишь</li><li>почти не работал, так, посверлил чуток, то убери за собой всё равно</li></ul></li><li><strong>Курим и вэйпим на улице</strong><ul><li>Даже если никого нет</li><li>Даже если на улице холодно</li><li>Мы так решили в марте 2018 года на голосовании (см. рассылку)</li></ul></li><li><strong>Уходишь последним – убери всё</strong><ul><li>Cовсем всё, не только своё</li><li>Да, не забудь про паяльный стол, сверлильный станок, верстаки и так далее</li><li>И про пол вокруг</li><li>Вымой все кружки, что остались, это несложно</li><li>Заодно проверь, не пора ли вынести мусор</li></ul></li></ul><p><img src="'+r+'" alt=""></p><h2 id="стеллажи" tabindex="-1">Стеллажи <a class="header-anchor" href="#стеллажи" aria-label="Permalink to &quot;Стеллажи&quot;">​</a></h2><ul><li>Личные вещи храни в личной коробке. Подписанной, и с красным стикером. Объём личных вещей — разумный (1-2 стандартные коробки). Если больше — будь готов к тому, что попросят ужаться</li><li>Не тащи к нам всякий хлам, который валяется у тебя в гараже/на балконе/антресолях. Если вещь не пригодилась тебе несколько лет, нам она тоже скорее всего не пригодится и попадет в кандидаты на выброс</li><li>Маркировка стикерами: <ul><li>красный: личные вещи</li><li>оранжевый: вещи в общем пользовании (внутри ХС, с возвратом)</li><li>зелёный: доступно для общего пользования (можно использовать без возврата)</li><li>жёлтый: поиск владельца</li></ul></li><li>Наклеивай желтый стикер с датой на все неподписанные коробки. Если хозяин за месяц не объявится, вещь национализируется (клеится зелёный/оранжевый). Либо перемещается в коробку «Кандидаты на выброс»</li><li>Если ты эксперт в каком-то сложном оборудовании, напиши своё имя на стикере и расшарь документацию</li></ul><h2 id="доступ" tabindex="-1">Доступ <a class="header-anchor" href="#доступ" aria-label="Permalink to &quot;Доступ&quot;">​</a></h2><ul><li>Хакерспейс — общественное место</li><li>Сюда можно зайти в любое время</li><li>Нельзя закрываться внутри. Если на сайте написано, что ХС открыт, значит, можно зайти в гости</li><li>В ХС есть постоянно включенная веб-камера, доступная участникам</li></ul><h1 id="принципы-важнее-правил" tabindex="-1">Принципы важнее правил <a class="header-anchor" href="#принципы-важнее-правил" aria-label="Permalink to &quot;Принципы важнее правил&quot;">​</a></h1>',11)])])}const q=i(o,[["render",s]]);export{p as __pageData,q as default};
